def clean_text(s):
    s=re.sub(r'<script[\s\S]*?</script>',' ',s,flags=re.I); s=re.sub(r'<style[\s\S]*?</style>',' ',s,flags=re.I); s=re.sub(r'<[^>]+>',' ',s); return re.sub(r'\s+',' ',html.unescape(s)).strip()
def ensure_fallbacks():
    PUBLIC.mkdir(exist_ok=True)
    for file,(title,summary) in CRITICAL.items():
        p=PUBLIC/file
        if not p.exists():
            p.write_text(f"""<!doctype html><html lang='en'><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>{html.escape(title)} - GoalOS</title><link rel='stylesheet' href='assets/goalos-ask-goalos-concierge-v19.css'></head><body style='margin:0;background:#071526;color:#f7f2e9;font-family:Inter,system-ui,sans-serif'><main style='max-width:900px;margin:12vh auto;padding:32px'><p style='color:#ffe66e;text-transform:uppercase;letter-spacing:.18em;font-weight:900'>GoalOS route</p><h1 style='font-size:clamp(44px,8vw,96px);line-height:.9;margin:0 0 20px'>{html.escape(title)}</h1><p style='font-size:22px;max-width:720px'>{html.escape(summary)}</p><p style='border:1px solid rgba(255,111,174,.45);border-radius:18px;padding:16px'>{BOUNDARY} {TOKEN_BOUNDARY}</p><p><a style='color:#6fffe2;font-weight:900' href='site-map.html'>Open all pages →</a> <a style='color:#6fffe2;font-weight:900' href='index.html'>Home →</a></p></main><script src='assets/goalos-ask-goalos-knowledge-v19.js'></script><script src='assets/goalos-ask-goalos-concierge-v19.js'></script></body></html>""",encoding='utf-8')
def title_of(p,text):
    raw=p.read_text(encoding='utf-8',errors='ignore');
    m=re.search(r'<title[^>]*>(.*?)</title>',raw,re.I|re.S)
    if m and m.group(1).strip(): return clean_text(m.group(1))[:90]
    h=re.search(r'<h1[^>]*>(.*?)</h1>',raw,re.I|re.S)
    if h and h.group(1).strip(): return clean_text(h.group(1))[:90]
    return p.stem.replace('-',' ').title()
def category_for(name,title):
    s=(name+' '+title).lower()
    if any(x in s for x in ['rsi','loop','bottleneck','flight-recorder','state-capacity']): return 'Loop → RSI'
    if any(x in s for x in ['contract-atlas','mainnet','contract-academy','proof-rail']): return 'Mainnet Contracts'
    if any(x in s for x in ['token','agialpha']): return 'Token Boundary'
    if any(x in s for x in ['trust','privacy','data-boundary','no-data','security','claim-boundary']): return 'Trust & Boundary'
    if any(x in s for x in ['proof-run','docket','evidence','reviewer','validator','ledger','gauntlet']): return 'Evidence & Review'
    if any(x in s for x in ['registry','site-map','site-health','search','pathfinder','docs','start','website']): return 'Navigation & Docs'
    if any(x in s for x in ['mission','jobs','node','agent','meta-agentic','capability']): return 'Mission & Work OS'
    return 'Additional'
def collect_routes():
    routes=[]
    for p in sorted(PUBLIC.glob('*.html')):
        if p.name.startswith('.') or p.name=='404.html': continue
        raw=p.read_text(encoding='utf-8',errors='ignore'); text=clean_text(raw); title=title_of(p,text); cat=category_for(p.name,title)
        words=[]
        for x in re.findall(r'[A-Za-z0-9$]{3,}',(title+' '+p.name+' '+text[:280])):
            xl=x.lower()
            if xl not in words: words.append(xl)
        routes.append({'title':title,'url':p.name,'category':cat,'summary':(text[:220] if text else title),'keywords':words[:42]})
    return routes
