def write_knowledge(routes):
    data={'meta':{'version':'v19','publicPages':len(routes),'intentCount':len(INTENTS),'externalActions':0,'boundary':BOUNDARY},'routes':routes,'intents':INTENTS}
    (ASSETS/'goalos-ask-goalos-knowledge-v19.js').write_text('window.GOALOS_ASK_GOALOS_KNOWLEDGE_V19 = '+json.dumps(data,separators=(',',':'))+';\n',encoding='utf-8')
    (PUBLIC/'search-index.json').write_text(json.dumps(routes,indent=2),encoding='utf-8')
    base='https://montrealai.github.io/goalos-agialpha-sovereign-machine-economy/'
    sm='<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n' + ''.join(f'  <url><loc>{base}{r["url"]}</loc></url>\n' for r in routes) + '</urlset>\n'
    (PUBLIC/'sitemap.xml').write_text(sm,encoding='utf-8')
def inject():
    head='<link rel="stylesheet" href="assets/goalos-ask-goalos-concierge-v19.css">'
    foot='<script src="assets/goalos-ask-goalos-knowledge-v19.js"></script><script src="assets/goalos-ask-goalos-concierge-v19.js"></script>'
    n=0
    for p in PUBLIC.glob('*.html'):
        raw=p.read_text(encoding='utf-8',errors='ignore')
        raw=re.sub(r'<link[^>]+goalos-ask-goalos-concierge-v1[89]\.css[^>]*>\s*','',raw,flags=re.I)
        raw=re.sub(r'<script[^>]+goalos-ask-goalos-knowledge-v1[89]\.js[^>]*>\s*</script>\s*','',raw,flags=re.I)
        raw=re.sub(r'<script[^>]+goalos-ask-goalos-concierge-v1[89]\.js[^>]*>\s*</script>\s*','',raw,flags=re.I)
        raw=re.sub(r'</head>',head+'\n</head>',raw,flags=re.I,count=1) if '</head>' in raw.lower() else head+'\n'+raw
        raw=re.sub(r'</body>',foot+'\n</body>',raw,flags=re.I,count=1) if '</body>' in raw.lower() else raw+'\n'+foot
        p.write_text(raw,encoding='utf-8'); n+=1
    return n
