def patch_readme():
    p=ROOT/'README.md'
    if p.exists():
        s=p.read_text(encoding='utf-8',errors='ignore')
        if 'Ask GoalOS Concierge V19' not in s:
            s += '\n\n## Ask GoalOS Concierge V19 — browser-local question routing\n\nUsers can ask questions directly on the website and receive an immediate browser-local answer with recommended routes. The concierge answers from the static GoalOS route index and curated proof-path knowledge. It does not call a model, submit a form, connect a wallet, store user data, or make a network request.\n\nBoundary: no user data, no user funds, no wallet, no transaction, no network call, no production authority, human review required.\n'
            p.write_text(s,encoding='utf-8')
