def main():
    ensure_fallbacks(); ask_page(); routes=collect_routes(); write_knowledge(routes); injected=inject(); routes=collect_routes(); write_knowledge(routes); patch_readme(); docs_and_reports(routes,injected); (PUBLIC/'.nojekyll').write_text('',encoding='utf-8'); print(json.dumps({'status':'passed','routes':len(routes),'pagesInjected':injected},indent=2))
